UnityUnrealC++Python <pre><code>// 1. Attach TryllAgentComponent to a GameObject.
//    Assign a TryllWorkflowAsset in the Inspector, or build the graph at runtime:
var graph = new TryllGraphBuilder()
    .AddNode("guard",  TryllNodeType.HumanMessageGuardrail)
    .AddNode("answer", TryllNodeType.Generate)
    .Wire("guard",  "triggered",     "END")
    .Wire("guard",  "not_triggered", "answer")
    .Wire("answer", "default",       "END")
    .SetStartNode("guard")
    .SetDefaultModelName("My Local Model")
    .Build();

var agentComp = GetComponent&lt;TryllAgentComponent&gt;();
agentComp.InlineGraphDescription = graph;

// 2. Wire events.
agentComp.OnAnswerText.AddListener(
    (text, isDelta, isFinal) =&gt; chatText.text += text);
agentComp.OnTurnComplete.AddListener(
    (status, _, _) =&gt; typingIndicator.SetActive(false));

// 3. When the agent is created, send the first message.
agentComp.OnAgentCreated.AddListener(() =&gt; agentComp.SendMessage("Hello!"));
</code></pre> <ol> <li>Add a <code>UTryllAgentComponent</code> to your actor.</li> <li>In the Details panel, edit Graph on the component, or    reference a <code>UTryllWorkflowAsset</code> you authored in the Content    Browser. Wire guard.triggered → END, guard.not_triggered    → answer, answer.default → END.</li> <li>In Blueprint:<ul> <li>Bind On Agent Ready to a handler that calls Send   Message.</li> <li>Bind On Answer Text to append each chunk to a UI text   block.</li> <li>Bind On Turn Complete to flip the "typing" indicator   off.</li> </ul> </li> </ol> <pre><code>#include &lt;tryll/TryllClient.h&gt;

namespace TC = Tryll::Client;

TC::GraphDescription graph;
graph.AddNode("guard",  TC::NodeType::HumanMessageGuardrail)
     .AddNode("answer", TC::NodeType::Generate)
     .Wire("guard",  "triggered",     "END")
     .Wire("guard",  "not_triggered", "answer")
     .Wire("answer", "default",       "END")
     .SetStartNode("guard")
     .SetDefaultModelName("My Local Model");

auto agent = client.CreateAgent(graph);

// Stream tokens to stdout as they arrive.
agent.SendText("Hello!",
    [](std::string_view text, bool /*isDelta*/, bool /*isFinal*/)
    { std::cout &lt;&lt; text &lt;&lt; std::flush; });
</code></pre> <pre><code>from tryll_client import GraphDescription, NodeType

# 1. Build the graph.
graph = (
    GraphDescription()
    .add_node("guard",  NodeType.HumanMessageGuardrail)
    .add_node("answer", NodeType.Generate)
    .wire("guard",  "triggered",     "END")      # drop jailbreaks silently
    .wire("guard",  "not_triggered", "answer")
    .wire("answer", "default",       "END")
    .set_start_node("guard")
    .set_default_model_name("My Local Model")
)

# 2. Create the agent.
agent = client.create_agent(graph)

# 3. Send a message. send_message blocks and returns the full reply.
reply = agent.send_message("Hello!")
print(reply)
</code></pre>

