    .wire("knowledge", "not_found", "answer")
    .wire("answer",    "default",   "END")
    .set_start_node("knowledge")
    .set_default_model_name("My Local Model")
)

agent = client.create_agent(graph)
</code></pre> <pre><code>namespace TC = Tryll::Client;

